// Recursive function to find sum of digits
int recursiveSum(int n) {
   if(n == 0) {
      return 0;
   }
   else {
      return n%10 + recursiveSum(n/10);
   }
}

// Iterative function to find sum of digits
int iterativeSum(int n) {
   int sum = 0;
   while(n != 0) {
      sum += abs(n%10);
      n /= 10;
   }
   return sum;
}

