import java.util.Scanner;

public class PercentageCalculator {

   public static void main(String[] args) {

      Scanner input = new Scanner(System.in);

      // Prompt user to enter a number
      System.out.print("Enter a number: ");

      // Check if input is a number, if not output an error message and exit
      if (!input.hasNextDouble()) {
           System.out.println("Invalid input. Please enter a valid number. ");
           return;
      }

      // Store user input as variable number
      double number = input.nextDouble();

      // Prompt user to enter a percentage
      System.out.print("Enter a percentage: ");

      // Check if input is a number, if not output an error message and exit
      if (!input.hasNextDouble()) {
           System.out.println("Invalid input. Please enter a valid percentage. ");
           return;
      }

      // Store user input as variable percent
      double percent = input.nextDouble();

      // Check if percent is negative, if yes output an error message and exit
      if (percent < 0) {
           System.out.println("Invalid input. Percentage cannot be negative. ");
           return;
      }

      // Calculate percentage using formula: percentage = (percent / 100) * number
      double result = (percent / 100) * number;

      // Output result, rounded to two decimal places
      System.out.printf("The result is: %.2f", result);

      // Close scanner object to prevent resource leak
      input.close();
   }
}
